import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { doctorAPI } from '../services/api';
import BookAppointment from '../components/BookAppointment';
import { 
  FaSearch, 
  FaFilter, 
  FaStar, 
  FaStarHalfAlt, 
  FaRegStar, 
  FaVideo, 
  FaCalendar,
  FaUserMd,
  FaMapMarkerAlt,
  FaLanguage,
  FaClock
} from 'react-icons/fa';

const Home = () => {
  const { t } = useTranslation();
  const [doctors, setDoctors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSpecialty, setSelectedSpecialty] = useState('');
  const [availableOnly, setAvailableOnly] = useState(false);
  
  // Appointment booking modal state
  const [isBookingModalOpen, setIsBookingModalOpen] = useState(false);
  const [selectedDoctor, setSelectedDoctor] = useState(null);

  // Dummy data for demonstration
  const dummyDoctors = [
    {
      id: '1',
      name: 'Dr. Rajesh Kumar',
      specialty: 'Cardiology',
      qualifications: 'MBBS, MD Cardiology',
      experience_years: 15,
      consultation_fee: 500,
      is_available: true,
      languages: 'English, Hindi, Punjabi',
      rating: 4.8,
      total_consultations: 1200,
      profile_image: null
    },
    {
      id: '2',
      name: 'Dr. Priya Sharma',
      specialty: 'Pediatrics',
      qualifications: 'MBBS, MD Pediatrics',
      experience_years: 10,
      consultation_fee: 400,
      is_available: true,
      languages: 'English, Hindi',
      rating: 4.6,
      total_consultations: 800,
      profile_image: null
    },
    {
      id: '3',
      name: 'Dr. Harpreet Singh',
      specialty: 'General Medicine',
      qualifications: 'MBBS, MD Internal Medicine',
      experience_years: 12,
      consultation_fee: 350,
      is_available: false,
      languages: 'English, Hindi, Punjabi',
      rating: 4.5,
      total_consultations: 950,
      profile_image: null
    },
    {
      id: '4',
      name: 'Dr. Sunita Devi',
      specialty: 'Gynecology',
      qualifications: 'MBBS, MS Gynecology',
      experience_years: 8,
      consultation_fee: 450,
      is_available: true,
      languages: 'English, Hindi, Punjabi',
      rating: 4.7,
      total_consultations: 600,
      profile_image: null
    }
  ];

  useEffect(() => {
    fetchDoctors();
  }, []);

  const fetchDoctors = async () => {
    try {
      setLoading(true);
      // For demo purposes, we'll use dummy data
      // In production, uncomment the API call below
      // const response = await doctorAPI.getAll();
      // setDoctors(response.data);
      
      // Simulate API delay
      setTimeout(() => {
        setDoctors(dummyDoctors);
        setLoading(false);
      }, 1000);
    } catch (error) {
      console.error('Error fetching doctors:', error);
      setError('Failed to load doctors');
      setDoctors(dummyDoctors); // Fallback to dummy data
      setLoading(false);
    }
  };

  const filteredDoctors = doctors.filter(doctor => {
    const matchesSearch = doctor.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         doctor.specialty.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesSpecialty = !selectedSpecialty || doctor.specialty === selectedSpecialty;
    const matchesAvailability = !availableOnly || doctor.is_available;
    
    return matchesSearch && matchesSpecialty && matchesAvailability;
  });

  const specialties = [...new Set(doctors.map(doctor => doctor.specialty))];

  const renderStars = (rating) => {
    const stars = [];
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 !== 0;
    const emptyStars = 5 - fullStars - (hasHalfStar ? 1 : 0);

    for (let i = 0; i < fullStars; i++) {
      stars.push(<FaStar key={`full-${i}`} className="star" />);
    }
    
    if (hasHalfStar) {
      stars.push(<FaStarHalfAlt key="half" className="star" />);
    }
    
    for (let i = 0; i < emptyStars; i++) {
      stars.push(<FaRegStar key={`empty-${i}`} className="star empty" />);
    }

    return stars;
  };

  const handleConsultNow = (doctorId) => {
    // In a real app, this would initiate a video call
    alert(`Starting video consultation with doctor ${doctorId}`);
  };

  const handleBookAppointment = (doctorId) => {
    const doctor = filteredDoctors.find(d => d.id === doctorId);
    setSelectedDoctor(doctor);
    setIsBookingModalOpen(true);
  };

  // Handle appointment booking submission
  const handleAppointmentSubmit = (appointmentData) => {
    console.log('Appointment booked:', appointmentData);
    // Here you would typically send the data to your backend
    // For now, we'll just log it and show success
  };

  // Handle booking modal close
  const handleBookingModalClose = () => {
    setIsBookingModalOpen(false);
    setSelectedDoctor(null);
  };

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-8">
        <div className="flex items-center justify-center min-h-64">
          <div className="loading"></div>
          <span className="ml-2">Loading doctors...</span>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-8">
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">
          {t('doctors')} {t('available')}
        </h1>
        <p className="text-gray-600">
          Find and consult with qualified doctors in your area
        </p>
      </div>

      {/* Search and Filters */}
      <div className="bg-white rounded-lg shadow-sm border p-6 mb-8">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          {/* Search */}
          <div className="relative">
            <FaSearch className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <input
              type="text"
              placeholder={`${t('search')} ${t('doctors').toLowerCase()}...`}
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="input pl-10"
            />
          </div>

          {/* Specialty Filter */}
          <div className="relative">
            <FaFilter className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
            <select
              value={selectedSpecialty}
              onChange={(e) => setSelectedSpecialty(e.target.value)}
              className="input pl-10"
            >
              <option value="">All Specialties</option>
              {specialties.map(specialty => (
                <option key={specialty} value={specialty}>{specialty}</option>
              ))}
            </select>
          </div>

          {/* Availability Filter */}
          <div className="flex items-center gap-3">
            <input
              type="checkbox"
              id="availableOnly"
              checked={availableOnly}
              onChange={(e) => setAvailableOnly(e.target.checked)}
              className="rounded border-gray-300 text-primary-color focus:ring-primary-color"
            />
            <label htmlFor="availableOnly" className="text-sm font-medium text-gray-700">
              {t('available')} only
            </label>
          </div>
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="bg-red-100 border border-red-300 text-red-700 p-4 rounded-lg mb-6">
          {error}
        </div>
      )}

      {/* Doctors Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredDoctors.map((doctor) => (
          <div key={doctor.id} className="card hover:shadow-lg transition-all duration-200">
            {/* Doctor Header */}
            <div className="flex items-start gap-4 mb-4">
              <div className="w-16 h-16 bg-gradient-to-br from-primary-color to-primary-dark rounded-full flex items-center justify-center text-white text-xl font-bold">
                {doctor.profile_image ? (
                  <img 
                    src={doctor.profile_image} 
                    alt={doctor.name}
                    className="w-full h-full rounded-full object-cover"
                  />
                ) : (
                  <FaUserMd />
                )}
              </div>
              
              <div className="flex-1">
                <h3 className="font-semibold text-lg text-gray-900">{doctor.name}</h3>
                <p className="text-primary-color font-medium">{doctor.specialty}</p>
                <p className="text-sm text-gray-600">{doctor.qualifications}</p>
              </div>

              {/* Availability Status */}
              <div className={`px-3 py-1 rounded-full text-xs font-medium ${
                doctor.is_available 
                  ? 'bg-green-100 text-green-800' 
                  : 'bg-red-100 text-red-800'
              }`}>
                {doctor.is_available ? t('available') : t('unavailable')}
              </div>
            </div>

            {/* Doctor Info */}
            <div className="space-y-3 mb-6">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <FaClock className="text-gray-400 text-sm" />
                  <span className="text-sm text-gray-600">
                    {doctor.experience_years} years experience
                  </span>
                </div>
                <div className="flex items-center gap-1">
                  <div className="rating">
                    {renderStars(doctor.rating)}
                  </div>
                  <span className="text-sm text-gray-600 ml-1">
                    ({doctor.total_consultations})
                  </span>
                </div>
              </div>

              <div className="flex items-center gap-2">
                <FaLanguage className="text-gray-400 text-sm" />
                <span className="text-sm text-gray-600">{doctor.languages}</span>
              </div>
            </div>

            {/* Action Buttons */}
            <div className="grid grid-cols-2 gap-3">
              <button
                onClick={() => handleConsultNow(doctor.id)}
                disabled={!doctor.is_available}
                className="btn btn-primary flex items-center justify-center gap-2"
              >
                <FaVideo className="text-sm" />
                {t('consult_now')}
              </button>
              
              <button
                onClick={() => handleBookAppointment(doctor.id)}
                className="btn btn-outline flex items-center justify-center gap-2"
              >
                <FaCalendar className="text-sm" />
                {t('book_appointment')}
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* No Results */}
      {filteredDoctors.length === 0 && !loading && (
        <div className="text-center py-12">
          <FaUserMd className="mx-auto text-6xl text-gray-300 mb-4" />
          <h3 className="text-xl font-medium text-gray-900 mb-2">No doctors found</h3>
          <p className="text-gray-600">
            Try adjusting your search criteria or filters
          </p>
        </div>
      )}

      {/* Book Appointment Modal */}
      <BookAppointment
        doctor={selectedDoctor}
        isOpen={isBookingModalOpen}
        onClose={handleBookingModalClose}
        onSubmit={handleAppointmentSubmit}
      />
    </div>
  );
};

export default Home;
